// This follows construction 5 from the paper

use crypto_bigint::{
    NonZero, RandomMod, U4096, const_prime_monty_params,
    modular::{ConstMontyForm, ConstMontyParams},
};
use rand::{SeedableRng, rngs::ChaCha20Rng};

/// Random seed. Change to take this as a command line argument later.
pub const SEED: u64 = 1;

const P_STR: &str = "";

/// Very large prime (RFC 7919, A.3).
pub const P: U4096 = U4096::from_be_hex(P_STR);

const_prime_monty_params!(ModP, U4096, P_STR, 2);

pub type P4096 = ConstMontyForm<ModP, { U4096::LIMBS }>;

/// Generator for a subgroup of size Q (of integers modulo P).
pub const G: P4096 = P4096::new(&U4096::from_u8(2));

/// Q = (p - 1) / 2.
///
/// Order of subgroup generated by G (modulo P).
/// Also a very large prime.
pub const Q: NonZero<U4096> = NonZero::<U4096>::new_unwrap(U4096::from_be_hex(
    "",
));

// #[derive(Debug)]
pub struct ElGamalPKE {
    rng: ChaCha20Rng,
}

impl ElGamalPKE {
    pub fn new() -> Self {
        Self {
            rng: ChaCha20Rng::seed_from_u64(SEED),
        }
    }

    /// Generates the `(pk, sk)` tuple.
    // gen is a reserved keyword in rust. We bypass this by using the r# syntax.
    //
    // Note that we need &mut self here instead of just &self because using self.rng requires
    // mutating self.rng.
    pub fn r#gen(&mut self) -> (U4096, U4096) {
        // sk = uniformly random integer < q
        let sk = U4096::random_mod_vartime(&mut self.rng, &Q);

        // pk = g^sk
        // We need to find a better way of handling modulo arithmetic that avoids overflow.
        // Maybe this crate? https://docs.rs/num-modular/0.6.1/num_modular/
        let pk = G.pow(&sk);

        // output (sk, pk)
        (sk, pk.retrieve())
    }

    /// Uses the public key `pk` to encode message `m`.
    /// Note that `m` must be in the message space, which is the cyclic group generated by `g` modulo `q`.
    // This could well be wrong.
    pub fn enc(&mut self, pk: U4096, m: U4096) -> Option<(U4096, U4096)> {
        if m == U4096::ZERO || &m >= ModP::PARAMS.modulus().as_ref() {
            // Message outside of message space.
            return None;
        }

        let m = P4096::new(&m);
        if m.pow(&Q) != P4096::ONE {
            // Message not in subgroup generated by g
            return None;
        }

        let pk = P4096::new(&pk);

        let r = U4096::random_mod_vartime(&mut self.rng, &Q);
        let c1 = m * pk.pow(&r);

        let c2 = G.pow(&r);

        Some((c1.retrieve(), c2.retrieve()))
    }

    /// Uses the secret key `sk` to decode some ciphertext `(c1, c2)`.
    // Need to find some way to get the modulo multiplicative inverse
    #[allow(unused)]
    pub fn dec(&self, sk: U4096, (c1, c2): (U4096, U4096)) -> U4096 {
        // output c1 * c2^(-sk)
        let c1 = P4096::new(&c1);
        let c2 = P4096::new(&c2);
        (c1 * c2.pow(&sk).invert().expect("Failed to invert")).retrieve()
    }
}

#[cfg(test)]
mod test {
    use crypto_bigint::U4096;

    use crate::el_gamal_pke::ElGamalPKE;

    #[test]
    fn verify_q() {
        assert_eq!(*super::Q, (super::P - U4096::ONE) / U4096::from_u8(2));
    }

    #[test]
    fn enc_dec_valid_1() {
        let mut pke = ElGamalPKE::new();
        let (sk, pk) = pke.r#gen();

        let m = U4096::from_u8(5);
        let (c1, c2) = pke.enc(pk, m).expect("m should be in subgroup");

        let m_dec = pke.dec(sk, (c1, c2));
        assert_eq!(m, m_dec);
    }
}
